/bin/bash -lc "cat > src/lib/gameEngine.test.ts <<'EOF'
import { describe, expect, it } from 'vitest';
import { mentalMathPrompts } from '../data/mentalMath';
import { speedConceptPrompts } from '../data/speedConcepts';
import { spotTheFlawPrompts } from '../data/spotTheFlaw';
import type { ChoicePrompt, GamePrompt, NumericPrompt } from './gameTypes';
import {
  BASE_CORRECT_POINTS,
  STREAK_BONUS_POINTS,
  advanceSession,
  buildPromptIndex,
  getCurrentPrompt,
  getProgressSummary,
  selectPromptIds,
  startGameSession,
  submitAnswer,
  validateAnswer,
} from './gameEngine';

describe('deterministic prompt selection', () => {
  it('returns the same ordered queue for the same seed', () => {
    const first = selectPromptIds(speedConceptPrompts, 6, 'daily-drill');
    const second = selectPromptIds(speedConceptPrompts, 6, 'daily-drill');

    expect(first).toEqual(second);
    expect(new Set(first).size).toBe(6);
  });

  it('cycles through local prompts when a round is longer than the fixture set', () => {
    const tinyFixture = speedConceptPrompts.slice(0, 2);
    const selected = selectPromptIds(tinyFixture, 5, 'cycle-test');

    expect(selected).toHaveLength(5);
    expect(selected.filter((id) => id === tinyFixture[0].id).length).toBeGreaterThan(1);
    expect(selected.every((id) => tinyFixture.some((prompt) => prompt.id === id))).toBe(true);
  });

  it('rejects an empty prompt set instead of starting a broken game', () => {
    expect(() => selectPromptIds([], 3, 'empty')).toThrow('without prompts');
  });
});

describe('answer validation by game type', () => {
  it('validates Speed Concepts matches and treats unknown choices as misses', () => {
    const prompt = speedConceptPrompts.find((candidate) => candidate.matchType === 'formula') as ChoicePrompt;

    expect(validateAnswer(prompt, prompt.correctChoiceId).correct).toBe(true);
    expect(validateAnswer(prompt, 'z')).toMatchObject({ correct: false, normalizedAnswer: 'z' });
  });

  it('validates Spot the Flaw choices and handles blank submissions deterministically', () => {
    const prompt = spotTheFlawPrompts.find((candidate) => candidate.flawDomain === 'trading') as ChoicePrompt;

    const correct = validateAnswer(prompt, prompt.correctChoiceId);
    const blank = validateAnswer(prompt, '   ');

    expect(correct.correct).toBe(true);
    expect(correct.correctAnswer).toContain('Ignoring transaction costs');
    expect(blank).toMatchObject({ correct: false, normalizedAnswer: '' });
  });

  it('validates Mental Math numeric answers with formatting and tolerance', () => {
    const dollarsPrompt = mentalMathPrompts.find((candidate) => candidate.id === 'math-trading-pnl-shares') as NumericPrompt;
    const percentPrompt = mentalMathPrompts.find((candidate) => candidate.id === 'math-percentages-down-up') as NumericPrompt;

    expect(validateAnswer(dollarsPrompt, '" '$130.00' "').correct).toBe(true);
    expect(validateAnswer(percentPrompt, '-1.45%').correct).toBe(true);
    expect(validateAnswer(percentPrompt, '-1.00').correct).toBe(false);
    expect(validateAnswer(dollarsPrompt, 'not a number')).toMatchObject({ correct: false, normalizedAnswer: 'not a number' });
  });
});

describe('game sessions, scoring, streaks, and completion', () => {
  function startControlledSession(prompts: GamePrompt[], roundLimit = prompts.length) {
    const session = startGameSession({
      gameId: prompts[0].gameId,
      prompts,
      roundLimit,
      durationSeconds: 60,
      seed: 'controlled-seed',
      startedAtMs: 1_000,
    });
    return { session, promptIndex: buildPromptIndex(prompts) };
  }

  it('awards base points and streak bonuses for consecutive correct answers', () => {
    const { promptIndex, session } = startControlledSession(speedConceptPrompts.slice(0, 2));

    const firstPrompt = getCurrentPrompt(session, promptIndex) as ChoicePrompt;
    const afterFirst = submitAnswer(session, promptIndex, firstPrompt.correctChoiceId, 2_000);
    expect(afterFirst.phase).toBe('feedback');
    expect(afterFirst.score).toBe(BASE_CORRECT_POINTS);
    expect(afterFirst.streak).toBe(1);

    const readyForSecond = advanceSession(afterFirst, 2_100);
    const secondPrompt = getCurrentPrompt(readyForSecond, promptIndex) as ChoicePrompt;
    const afterSecond = submitAnswer(readyForSecond, promptIndex, secondPrompt.correctChoiceId, 3_000);

    expect(afterSecond.phase).toBe('complete');
    expect(afterSecond.completionReason).toBe('round-limit');
    expect(afterSecond.score).toBe(BASE_CORRECT_POINTS * 2 + STREAK_BONUS_POINTS);
    expect(afterSecond.bestStreak).toBe(2);
  });

  it('resets streak on a miss while preserving the best streak', () => {
    const { promptIndex, session } = startControlledSession(spotTheFlawPrompts.slice(0, 2));
    const firstPrompt = getCurrentPrompt(session, promptIndex) as ChoicePrompt;
    const afterFirst = submitAnswer(session, promptIndex, firstPrompt.correctChoiceId, 2_000);
    const readyForSecond = advanceSession(afterFirst, 2_100);
    const afterMiss = submitAnswer(readyForSecond, promptIndex, 'wrong-choice', 3_000);

    expect(afterMiss.phase).toBe('complete');
    expect(afterMiss.score).toBe(BASE_CORRECT_POINTS);
    expect(afterMiss.streak).toBe(0);
    expect(afterMiss.bestStreak).toBe(1);
    expect(afterMiss.lastResult?.correct).toBe(false);
  });

  it('summarizes completed rounds with category-level review data', () => {
    const prompts = mentalMathPrompts.slice(0, 2);
    const { promptIndex, session } = startControlledSession(prompts);
    const firstPrompt = getCurrentPrompt(session, promptIndex) as NumericPrompt;
    const afterFirst = submitAnswer(session, promptIndex, firstPrompt.expectedValue, 2_000);
    const readyForSecond = advanceSession(afterFirst, 2_100);
    const secondPrompt = getCurrentPrompt(readyForSecond, promptIndex) as NumericPrompt;
    const complete = submitAnswer(readyForSecond, promptIndex, secondPrompt.expectedValue, 3_000);
    const summary = getProgressSummary(complete, 3_000);

    expect(summary).toMatchObject({ answered: 2, correct: 2, score: BASE_CORRECT_POINTS * 2 + STREAK_BONUS_POINTS });
    expect(summary.categoryBreakdown.arithmetic).toEqual({ answered: 2, correct: 2 });
  });

  it('finishes by timer without recording a phantom answer', () => {
    const session = startGameSession({
      gameId: 'mental-math-speed',
      prompts: mentalMathPrompts.slice(0, 1),
      roundLimit: 1,
      durationSeconds: 1,
      seed: 'timer-edge',
      startedAtMs: 1_000,
    });
    const complete = submitAnswer(session, buildPromptIndex(mentalMathPrompts.slice(0, 1)), '888', 2_001);

    expect(complete.phase).toBe('complete');
    expect(complete.completionReason).toBe('timer-expired');
    expect(complete.attempts).toHaveLength(0);
  });
});
EOF"

