import type { GameId } from './gameTypes';
import type { GameSession, ProgressSummary } from './gameEngine';

const STORAGE_KEY = 'quant-interview-prep:mini-game-progress:v1';
const MAX_ATTEMPTS = 30;

export interface GameAttemptRecord {
  id: string;
  gameId: GameId;
  gameTitle: string;
  completedAtIso: string;
  score: number;
  correct: number;
  total: number;
  accuracy: number;
  bestStreak: number;
  secondsUsed: number;
  completionReason?: string;
}

export interface MiniGameProgress {
  attempts: GameAttemptRecord[];
}

export const emptyProgress: MiniGameProgress = { attempts: [] };

function canUseLocalStorage(): boolean {
  try {
    return typeof window " '!== ' "'undefined' && typeof window.localStorage " '!== ' "'undefined';
  } catch {
    return false;
  }
}

function parseProgress(raw: string | null): MiniGameProgress {
  if (" '!raw) {
    return emptyProgress;
  }

  try {
    const parsed = JSON.parse(raw) as Partial<MiniGameProgress>;
    if (!Array.isArray(parsed.attempts)) {
      return emptyProgress;
    }

    return {
      attempts: parsed.attempts
        .filter((attempt): attempt is GameAttemptRecord => Boolean(attempt && typeof attempt.id === ' "'string'))
        .slice(0, MAX_ATTEMPTS),
    };
  } catch {
    return emptyProgress;
  }
}

export function readMiniGameProgress(): MiniGameProgress {
  if (" '!canUseLocalStorage()) {
    return emptyProgress;
  }

  return parseProgress(window.localStorage.getItem(STORAGE_KEY));
}

export function writeMiniGameProgress(progress: MiniGameProgress): void {
  if (!canUseLocalStorage()) {
    return;
  }

  window.localStorage.setItem(
    STORAGE_KEY,
    JSON.stringify({ attempts: progress.attempts.slice(0, MAX_ATTEMPTS) }),
  );
}

export function createAttemptRecord(
  session: GameSession,
  gameTitle: string,
  summary: ProgressSummary,
): GameAttemptRecord {
  return {
    id: session.id,
    gameId: session.gameId,
    gameTitle,
    completedAtIso: new Date(session.completedAtMs ?? Date.now()).toISOString(),
    score: summary.score,
    correct: summary.correct,
    total: summary.total,
    accuracy: summary.accuracy,
    bestStreak: summary.bestStreak,
    secondsUsed: summary.secondsUsed,
    completionReason: summary.completionReason,
  };
}

export function recordCompletedAttempt(record: GameAttemptRecord): MiniGameProgress {
  const current = readMiniGameProgress();
  const withoutDuplicate = current.attempts.filter((attempt) => attempt.id !== record.id);
  const nextProgress = {
    attempts: [record, ...withoutDuplicate].slice(0, MAX_ATTEMPTS),
  };
  writeMiniGameProgress(nextProgress);
  return nextProgress;
}

export function getRecentAttempt(progress: MiniGameProgress, gameId: GameId): GameAttemptRecord | undefined {
  return progress.attempts.find((attempt) => attempt.gameId === gameId);
}

export function getBestAttempt(progress: MiniGameProgress, gameId: GameId): GameAttemptRecord | undefined {
  return progress.attempts
    .filter((attempt) => attempt.gameId === gameId)
    .sort((left, right) => right.score - left.score || right.accuracy - left.accuracy)[0];
}
