export type Difficulty = 'warmup' | 'core' | 'stretch';

export type ContentStatus = 'original-generated' | 'reviewed-original';

export interface SourceMetadata {
  status: ContentStatus;
  sourceType: 'local-original-seed';
  note: string;
  updatedAt: string;
}

export interface ChoiceOption {
  id: string;
  label: string;
}

export interface PromptBase {
  id: string;
  gameId: GameId;
  category: string;
  skillTarget: string;
  prompt: string;
  explanation: string;
  difficulty: Difficulty;
  source: SourceMetadata;
}

export interface ChoicePrompt extends PromptBase {
  kind: 'choice';
  choices: ChoiceOption[];
  correctChoiceId: string;
}

export interface NumericPrompt extends PromptBase {
  kind: 'numeric';
  expectedValue: number;
  tolerance: number;
  answerUnit: string;
  workedSolution: string;
}

export interface SpeedConceptPrompt extends ChoicePrompt {
  gameId: 'speed-concepts';
  matchType: 'definition' | 'formula' | 'use-case' | 'interview-example';
  concept: string;
}

export interface SpotTheFlawPrompt extends ChoicePrompt {
  gameId: 'spot-the-flaw';
  flawDomain: 'probability' | 'statistics' | 'machine-learning' | 'trading';
  flawedArgument: string;
}

export interface MentalMathPrompt extends NumericPrompt {
  gameId: 'mental-math-speed';
  calculationType:
    | 'arithmetic'
    | 'fractions'
    | 'percentages'
    | 'logs-approximations'
    | 'probability-arithmetic'
    | 'expected-value'
    | 'trading-calculations';
}

export type GamePrompt = SpeedConceptPrompt | SpotTheFlawPrompt | MentalMathPrompt;

export interface GameDefinition {
  id: GameId;
  title: string;
  tagline: string;
  description: string;
  route: string;
  estimatedMinutes: number;
  roundLimit: number;
  durationSeconds: number;
  skillTargets: string[];
  practiceValue: string;
}
EOF

